import gurobipy as gp
from gurobipy import GRB

def solve_transportation_problem(Cities, Links, Products, Supply, Demand, ShipmentCost, Capacity, JointCapacity):
    # Create model
    model = gp.Model("MultiProductTransportation")

    # Create decision variables: x[i,j,p] = units of product p shipped from i to j
    x = model.addVars(
        [(i, j, p) for i, j in Links for p in Products],
        vtype=GRB.INTEGER,
        name="x"
    )

    # Set objective: minimize total shipping cost
    model.setObjective(
        gp.quicksum(ShipmentCost[i, j, p] * x[i, j, p] for i, j in Links for p in Products),
        GRB.MINIMIZE
    )

    # Add supply constraints
    for i in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for j in Cities if (i, j) in Links) <= Supply[Cities.index(i)][p_idx],
                name=f"Supply_{i}_{p}"
            )

    # Add demand constraints
    for j in Cities:
        for p_idx, p in enumerate(Products):
            model.addConstr(
                gp.quicksum(x[i, j, p] for i in Cities if (i, j) in Links) >= Demand[Cities.index(j)][p_idx],
                name=f"Demand_{j}_{p}"
            )

    # Add product capacity constraints
    for i, j in Links:
        for p in Products:
            model.addConstr(
                x[i, j, p] <= Capacity[i, j, p],
                name=f"ProdCapacity_{i}_{j}_{p}"
            )

    # Add joint capacity constraints
    for i, j in Links:
        model.addConstr(
            gp.quicksum(x[i, j, p] for p in Products) <= JointCapacity[i, j],
            name=f"JointCapacity_{i}_{j}"
        )

    # Solve the model
    model.optimize()

    # Return results
    if model.status == GRB.OPTIMAL:
        total_cost = model.objVal
        shipment_plan = []
        for i, j, p in x.keys():
            if x[i, j, p].x > 0:
                shipment_plan.append((i, j, p, x[i, j, p].x))
        return total_cost, shipment_plan
    else:
        return None, None

# Example usage with the provided data
if __name__ == "__main__":
    # Input data
    Cities = ["A", "B"]
    Links = [("A", "B")]
    Products = ["Product1"]
    Supply = [[10], [0]]  # Supply[i][p] for city i and product p
    Demand = [[0], [10]]  # Demand[i][p] for city i and product p

    # Convert to dictionary format for clarity
    ShipmentCost = {("A", "B", "Product1"): 1}
    Capacity = {("A", "B", "Product1"): 10}
    JointCapacity = {("A", "B"): 10}

    # Solve the problem
    total_cost, shipment_plan = solve_transportation_problem(
        Cities, Links, Products, Supply, Demand, 
        ShipmentCost, Capacity, JointCapacity
    )

    # Output results
    if total_cost is not None:
        print(f"Optimal solution found. Total cost: {total_cost}")
        print("Shipping plan:")
        for i, j, p, units in shipment_plan:
            print(f"Ship {units} units of {p} from {i} to {j}")
    else:
        print("No optimal solution found.")

import gurobipy as gp
from gurobipy import GRB

# Define trucks and routes
trucks = [1, 2, 3, 4, 5, 6, 7, 8]
routes = [1, 2, 3, 4, 5, 6, 7, 8]
segments = [1, 2, 3, 4, 5, 6, 7, 8]

# Define truck itineraries: (route, time) for each segment
itineraries = {
    1: [(8, 3), (6, 4), (7, 8), (4, 6), (3, 1), (2, 6), (5, 8), (1, 10)],
    2: [(5, 7), (6, 10), (2, 6), (1, 9), (8, 3), (7, 1), (4, 8), (3, 7)],
    3: [(8, 8), (7, 3), (4, 2), (3, 9), (1, 9), (6, 7), (5, 10), (2, 5)],
    4: [(4, 4), (1, 10), (8, 5), (7, 7), (6, 8), (3, 9), (2, 5), (5, 2)],
    5: [(1, 8), (8, 7), (3, 9), (4, 1), (5, 7), (2, 5), (7, 8), (6, 3)],
    6: [(7, 7), (6, 10), (4, 3), (8, 6), (3, 1), (2, 7), (5, 8), (1, 8)],
    7: [(5, 10), (1, 6), (6, 3), (2, 3), (3, 8), (7, 2), (8, 2), (4, 3)],
    8: [(1, 3), (2, 5), (6, 7), (7, 8), (8, 5), (3, 9), (5, 1), (4, 3)]
}

# Create model
model = gp.Model("Truck_Scheduling")

# Decision Variables
start = {}
end = {}
for t in trucks:
    for s in segments:
        start[t, s] = model.addVar(vtype=GRB.CONTINUOUS, name=f"start_{t}_{s}")
        end[t, s] = model.addVar(vtype=GRB.CONTINUOUS, name=f"end_{t}_{s}")

# Makespan variable
makespan = model.addVar(vtype=GRB.CONTINUOUS, name="makespan")

# Disjunctive variables
y = {}
for t1 in trucks:
    for s1 in segments:
        for t2 in trucks:
            for s2 in segments:
                if t1 != t2 and itineraries[t1][s1-1][0] == itineraries[t2][s2-1][0]:
                    y[t1, s1, t2, s2] = model.addVar(vtype=GRB.BINARY, name=f"y_{t1}_{s1}_{t2}_{s2}")

# Big-M value (upper bound on makespan)
M = sum(time for t in trucks for (route, time) in itineraries[t])

# Objective: Minimize makespan
model.setObjective(makespan, GRB.MINIMIZE)

# Constraints
# Segment ordering
for t in trucks:
    for s in segments[1:]:
        model.addConstr(start[t, s] >= end[t, s-1], f"order_{t}_{s}")

# Segment duration
for t in trucks:
    for s in segments:
        route, time = itineraries[t][s-1]
        model.addConstr(end[t, s] == start[t, s] + time, f"duration_{t}_{s}")

# Route conflict resolution
for t1 in trucks:
    for s1 in segments:
        for t2 in trucks:
            for s2 in segments:
                if t1 < t2 and itineraries[t1][s1-1][0] == itineraries[t2][s2-1][0]:
                    model.addConstr(
                        start[t1, s1] >= end[t2, s2] - M * (1 - y[t1, s1, t2, s2]),
                        f"disjunctive1_{t1}_{s1}_{t2}_{s2}"
                    )
                    model.addConstr(
                        start[t2, s2] >= end[t1, s1] - M * y[t1, s1, t2, s2],
                        f"disjunctive2_{t1}_{s1}_{t2}_{s2}"
                    )

# Makespan definition
for t in trucks:
    model.addConstr(makespan >= end[t, segments[-1]], f"makespan_{t}")

# Optimize the model
model.optimize()

# Print solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {model.objVal}")
    for t in trucks:
        print(f"Truck {t}:")
        for s in segments:
            print(f"  Segment {s}: Route {itineraries[t][s-1][0]}, Start: {start[t, s].x}, End: {end[t, s].x}")
else:
    print("No optimal solution found.")

